import{_ as a,c as o,o as t,ae as r}from"./chunks/framework.Cqi9LMMK.js";const u=JSON.parse('{"title":"Расширение браузера","description":"","frontmatter":{"title":"Расширение браузера"},"headers":[],"relativePath":"guide/extension.md","filePath":"guide/extension.md"}'),i={name:"guide/extension.md"};function l(n,e,s,h,d,c){return t(),o("div",null,[...e[0]||(e[0]=[r('<h3 id="расширение-для-chrome-edge" tabindex="-1">Расширение для Chrome / Edge <a class="header-anchor" href="#расширение-для-chrome-edge" aria-label="Permalink to &quot;Расширение для Chrome / Edge&quot;">​</a></h3><blockquote><p>Основной способ запуска Vue Inspector с поддержкой автоматического запуска, оконного режима, popup-меню и интеграции в браузер.</p></blockquote><h2 id="хранение-данных" tabindex="-1">Хранение данных <a class="header-anchor" href="#хранение-данных" aria-label="Permalink to &quot;Хранение данных&quot;">​</a></h2><p>Настройки и сохранённые медиафайлы живут в <strong>хранилищах профиля браузера</strong> (отдельно от сайтов, которые вы инспектируете): один раз сохранили в Options — те же данные на всех вкладках. Сравнение со standalone и детали по типам данных — на странице <a href="./install.html#storage">Установка → Где хранятся настройки</a>.</p><hr><h2 id="установка" tabindex="-1">Установка <a class="header-anchor" href="#установка" aria-label="Permalink to &quot;Установка&quot;">​</a></h2><ol><li>Перейдите в <a href="../../../index.html#installation" target="_self" rel="noopener">раздел установки</a> на главной странице сайта.</li><li>Скачайте последнюю версию расширения;</li><li>Распакуйте архив в удобную папку;</li><li>Откройте страницу <code>chrome://extensions/</code>;</li><li>Включите <strong>Режим разработчика</strong> в правом верхнем углу;</li><li>Нажмите <strong>Загрузить распакованное расширение</strong>;</li><li>Выберите папку с расширением.</li></ol><hr><h2 id="использование" tabindex="-1">Использование <a class="header-anchor" href="#использование" aria-label="Permalink to &quot;Использование&quot;">​</a></h2><p>После установки расширение будет доступно в браузере и может запускаться в соответствии с текущими пользовательскими настройками.</p><p>При необходимости запуск доступен через popup-меню расширения.</p><hr><h2 id="режим-инкогнито" tabindex="-1">Режим инкогнито <a class="header-anchor" href="#режим-инкогнито" aria-label="Permalink to &quot;Режим инкогнито&quot;">​</a></h2><p>Если требуется работа в режиме инкогнито:</p><ol><li>Откройте страницу <code>chrome://extensions/</code>;</li><li>Найдите <strong>Vue Inspector</strong> в списке установленных расширений;</li><li>Откройте параметры расширения (Details);</li><li>Включите опцию <strong>Разрешить использование в режиме инкогнито</strong>.</li></ol><p>После этого расширение будет доступно и в приватных окнах браузера.</p>',16)])])}const m=a(i,[["render",l]]);export{u as __pageData,m as default};
